PublicAPI.CRM.Contractor.AddComment(contractor, comment, author);

//загружаем контрагента по идентификатору
var contractor = PublicAPI.CRM.Contractor.Load(3); 

//создаем контакт
var myContact = PublicAPI.CRM.Contractor.CreateContact(contractor);

//myContact - созданный контакт

//ВНИМАНИЕ!! Контакт создается без имени. Для корректной работы с контактом нужно указать его имя и сохранить сущность в базу данных
myContact.Name = "Имя для контакта";
myContact.Save();

//загружаем контрагента по идентификатору
var contractor = PublicAPI.CRM.Contractor.Load(3); 

//создаем сделку
var mySale = PublicAPI.CRM.Contractor.CreateSale(contractor);

//mySale - созданная сделка

//ВНИМАНИЕ!! Сделка создается без имени. Для корректной работы со сделкой нужно указать её имя и сохранить сущность в базу данных
mySale.Name = "Имя для сделки";
mySale.Save();

member.remarks:
* - обязательный параметр Параметры: [0]*: Взаимоотношение (IRelationship) [1]*: Статус участника события (int)
Допустимые значения: - "Участник" (0) - "Информируемый" (1)
Результат: Список пользователей, являющимися участниками взаимоотношения с указанным статусом.
Пример: Пусть Relationship - переменная типа "Взаимоотношение". Тогда чтобы получить список участников события необходимо выполнить: {GetRelationshipMembers({Relationship};0)}
Чтобы вывести участников, которых необходимо информировать: {GetRelationshipMembers({Relationship};1)}
